// ── Đọc payload từ BE ──
const rawInput = $input.first().json.body ?? $input.first().json;
const body = typeof rawInput === 'string' ? JSON.parse(rawInput) : rawInput;

const endpoints = body.endpoints;
if (!Array.isArray(endpoints) || endpoints.length === 0) {
  throw new Error('Payload thiếu mảng endpoints hoặc rỗng.');
}

const callbackUrl = body.callbackUrl ?? '';
const callbackApiKey = body.callbackApiKey ?? '';
const globalBusinessRules = body.globalBusinessRules ?? '';
const endpointBusinessContexts = body.endpointBusinessContexts ?? {};
const testSuiteId = body.testSuiteId ?? '';
const promptConfig = body.promptConfig ?? {};
const srsRequirements = Array.isArray(body.srsRequirements) ? body.srsRequirements : [];
const model = body.model || 'gpt-4.1-mini';
const maxOutputTokens = Number(body.maxOutputTokens || 4096);
const preferJsonObjectResponse = body.preferJsonObjectResponse !== false;

return [{
  json: {
    endpoints,
    callbackUrl,
    callbackApiKey,
    globalBusinessRules,
    endpointBusinessContexts,
    testSuiteId,
    promptConfig,
    srsRequirements,
    model,
    maxOutputTokens,
    preferJsonObjectResponse
  }
}];

const input = $input.first().json;
const { endpoints, globalBusinessRules, endpointBusinessContexts, promptConfig, srsRequirements } = input;

// ── Ưu tiên đọc prompt từ backend (promptConfig) nếu có ──
const hasBackendPrompt = promptConfig
  && (promptConfig.systemPrompt || promptConfig.rules || promptConfig.responseFormat);

// ── Xây dựng mô tả endpoint gọn để giảm token ──
const epLines = endpoints.map((ep, i) => {
  const ctx = endpointBusinessContexts?.[ep.endpointId]
    ? `\n   Business context: ${endpointBusinessContexts[ep.endpointId]}`
    : '';
  const epPrompt = ep.prompt?.combinedPrompt
    ? `\n   Prompt: ${ep.prompt.combinedPrompt.substring(0, 700)}`
    : '';
  const deps = ep.dependsOnEndpointIds?.length > 0
    ? `\n   DependsOn: [${ep.dependsOnEndpointIds.join(', ')}]` : '';
  const auth = ep.isAuthRelated ? ' [AUTH-RELATED]' : '';
  const schemas = (ep.parameterSchemaPayloads?.length > 0 || ep.responseSchemaPayloads?.length > 0)
    ? `\n   Schemas: params=${JSON.stringify(ep.parameterSchemaPayloads ?? [])}; responses=${JSON.stringify(ep.responseSchemaPayloads ?? [])}`
    : '';
  return `${i + 1}. [ID=${ep.endpointId}] ${ep.httpMethod} ${ep.path}${auth}${deps}${ctx}${epPrompt}${schemas}`;
}).join('\n');

const srsLines = Array.isArray(srsRequirements) && srsRequirements.length > 0
  ? '=== SRS REQUIREMENTS ===\n' + srsRequirements.map(r => `[${r.id}] ${r.code ?? ''} ${r.title ?? ''}: ${r.effectiveConstraints ?? r.description ?? ''}`).join('\n')
  : '';

let systemPrompt;
let userPrompt;

if (hasBackendPrompt) {
  systemPrompt = promptConfig.systemPrompt
    || 'You are a senior QA engineer specializing in REST API test generation. Generate robust, executable, deterministic test cases and return ONLY raw JSON.';

  const taskInstruction = promptConfig.taskInstruction || '';
  const rules = promptConfig.rules || '';
  const responseFormat = promptConfig.responseFormat || '';

  userPrompt = [taskInstruction, '=== ENDPOINTS ===\n' + epLines, srsLines, rules, responseFormat]
    .filter(Boolean).join('\n\n');

} else {
  const rulesSection = globalBusinessRules
    ? `\n\n=== GLOBAL BUSINESS RULES ===\n${globalBusinessRules}` : '';

  systemPrompt = 'You are a senior QA engineer specialising in REST API automated testing. Return ONLY raw JSON.';

  userPrompt = `Generate exactly 3 test cases per endpoint when possible: HappyPath, Boundary, Negative.${rulesSection}

=== ENDPOINTS ===
${epLines}

${srsLines}

Rules: endpointId must match input UUID. request.body is serialized JSON or null. expectedStatus is an integer array. Use {{tcUniqueId}} for unique data. Populate coveredRequirementIds when SRS applies.

Response JSON shape: {"testCases":[{"endpointId":"uuid","name":"short","description":"one sentence","testType":"HappyPath|Boundary|Negative","priority":"High|Medium|Low","orderIndex":0,"tags":[],"request":{"httpMethod":"GET","url":"/path","headers":{},"pathParams":{},"queryParams":{},"bodyType":"None|JSON","body":null,"timeout":30000},"expectation":{"expectedStatus":[200],"responseSchema":null,"headerChecks":{},"bodyContains":[],"bodyNotContains":[],"jsonPathChecks":{},"maxResponseTime":null},"variables":[],"coveredRequirementIds":[],"traceabilityScore":0.9,"mappingRationale":""}],"model":"model","tokensUsed":0,"reasoning":"brief"}`;
}

const maxTokens = Math.max(1024, Math.min(Number(input.maxOutputTokens || 4096), 8192));
const openAiBody = {
  model: input.model || 'gpt-4.1-mini',
  temperature: 0.1,
  max_tokens: maxTokens,
  response_format: input.preferJsonObjectResponse === false ? undefined : { type: 'json_object' },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};

if (!openAiBody.response_format) delete openAiBody.response_format;

return [{
  json: {
    openAiBody,
    userPrompt,
    systemPrompt,
    originalInput: input
  }
}];

// ── Đọc response (hỗ trợ cả AI Agent lẫn HTTP Request tới OpenAI) ──
const response = $input.first().json;

if (response.error) {
  throw new Error(`OpenAI API error: ${response.error.message ?? JSON.stringify(response.error)}`);
}

// AI Agent node trả về { output: '...' }
// HTTP Request node trả về { choices: [{message:{content:'...'}}] }
const rawContent = response.output
  ?? response.choices?.[0]?.message?.content
  ?? null;

if (!rawContent) {
  throw new Error('LLM trả về response rỗng hoặc không đúng format. Keys: ' + Object.keys(response).join(', '));
}

// ── Loại bỏ markdown code block nếu có ──
let cleaned = rawContent.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/^```(?:json)?\s*\n?/, '').replace(/\n?```\s*$/, '').trim();
}

// ── Parse JSON ──
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Không parse được JSON từ LLM. Error: ${e.message}\nRaw (500 chars): ${cleaned.substring(0, 500)}`);
}

const testCases = parsed.testCases;
if (!Array.isArray(testCases) || testCases.length === 0) {
  throw new Error('LLM response thiếu mảng testCases hoặc rỗng.');
}

// ── Chuẩn hóa orderIndex ──
testCases.sort((a, b) => (a.orderIndex ?? 0) - (b.orderIndex ?? 0));
testCases.forEach((tc, i) => { tc.orderIndex = i; });

// ── Đảm bảo email unique bằng timestamp + random suffix ──
const ts = Date.now().toString(36);
const rnd = () => Math.random().toString(36).substring(2, 6);
testCases.forEach(tc => {
  if (tc.request && tc.request.body && typeof tc.request.body === 'string') {
    tc.request.body = tc.request.body.replace(
      /([\"\'\"]?email[\"\'\"]?\s*:\s*[\"\'\"])([^\"\'@]+)@/gi,
      (match, prefix, local) => `${prefix}${local}_${ts}${rnd()}@`
    );
  }
});

// ── Đảm bảo các field bắt buộc ──
testCases.forEach(tc => {
  if (!tc.endpointId) throw new Error('TestCase thiếu endpointId trong LLM response.');
  tc.testType = tc.testType ?? 'HappyPath';
  tc.priority = tc.priority ?? 'Medium';
  if (!tc.request) tc.request = { httpMethod: 'GET', url: '/', bodyType: 'None', timeout: 30000 };
  if (!tc.expectation) tc.expectation = { expectedStatus: '[200]' };
});

// ── Đọc callbackUrl & callbackApiKey từ node Parse Input ──
const inputNode = $('Parse Input').first().json;
const callbackUrl = inputNode.callbackUrl ?? '';
const callbackApiKey = inputNode.callbackApiKey ?? '';

if (!callbackUrl || !callbackUrl.startsWith('http')) {
  throw new Error('callbackUrl rỗng hoặc không hợp lệ: "' + callbackUrl + '". Hãy kiểm tra BeBaseUrl trong appsettings.json của BE.');
}

return [{
  json: {
    testCases,
    callbackUrl,
    callbackApiKey
  }
}];
